/* ── Merge les posts d'un utilisateur reçus depuis Firebase ── */
function _gwMergePost(snap) {
  if (!snap) return;
  var fbKey = snap.key;
  var posts = snap.val();
  if (!Array.isArray(posts) || !posts.length) return;
  var email = fbKey.replace(/__d__/g, '.').replace(/__a__/g, '@');

  /* Sauvegarde dans localStorage */
  try { localStorage.setItem(_userPostsKey(email), JSON.stringify(posts)); } catch(e){}

  /* Merger dans DEMO_POSTS (sans doublons) */
  var changed = false;
  posts.forEach(function(p) {
    if (!p || !p.id) return;
    if (!p.images) p.images = [];
    var existing = DEMO_POSTS.find(function(d){ return d.id === p.id; });
    if (!existing) {
      p.likers = loadPostLikers(p.id);
      DEMO_POSTS.push(p);
      changed = true;
    } else if (p.video && p.video.url && existing.video && !existing.video.url) {
      /* Met à jour l'URL vidéo si Firebase en a une mais pas la version locale */
      existing.video.url = p.video.url;
      var _vEl = document.getElementById('fv-' + p.id);
      if (_vEl && !_vEl.src) _vEl.src = p.video.url;
      changed = true;
    }
  });
  if (changed) {
    DEMO_POSTS.sort(function(a, b){ return b.id - a.id; });
    try {
      if (document.getElementById('feed-list')) renderFeed(getAllPosts());
    } catch(e){}
  }
}


/* ── Merge messages d'un groupe depuis Firebase ── */
function _gwMergeGroupMsg(snap) {
  if (!_currentUser || !snap) return;
  var fbKey = snap.key;
  var data  = snap.val();
  if (!data) return;
  var lsKey = fbKey.replace(/__d__/g, '.').replace(/__a__/g, '@');
  /* S'assurer que les conversations de groupe sont chargées avant la recherche */
  if (!_groupConvsReady) { try { _loadGroupConvs(); } catch(e){} }
  /* Vérifier que ce groupe concerne l'utilisateur courant */
  var conv = DEMO_CONVERSATIONS.find(function(c) {
    return c.isGroup && _getGroupMsgKey(c.projId, c.projOwnerEmail) === lsKey;
  });
  if (!conv) return;
  try {
    /* Normalise : Firebase stocke les messages comme objet {id:msg} ou tableau */
    var rawMsgs = data.messages;
    var incomingMsgs = Array.isArray(rawMsgs) ? rawMsgs
      : (rawMsgs && typeof rawMsgs === 'object') ? Object.values(rawMsgs) : [];
    if (!incomingMsgs.length) return;

    var existing = null;
    try { existing = JSON.parse(localStorage.getItem(lsKey)); } catch(e){}
    var stored = (existing && Array.isArray(existing.messages)) ? existing.messages : [];
    var storedMap = {};
    stored.forEach(function(m) { storedMap[String(m.id)] = true; });
    var newMsgsGrp = [];
    incomingMsgs.forEach(function(m) {
      if (m && m.id && !storedMap[String(m.id)]) { stored.push(m); newMsgsGrp.push(m); }
    });
    var changed = newMsgsGrp.length > 0;
    if (changed) {
      stored.sort(function(a, b) { return (Number(a.id)||0) - (Number(b.id)||0); });
      var _lastGrpMsg = newMsgsGrp[newMsgsGrp.length - 1];
      var _lastGrpText = _lastGrpMsg.text || (data.lastMsg || '');
      try { localStorage.setItem(lsKey, JSON.stringify({ messages: stored, lastMsg: _lastGrpText, lastAt: data.lastAt || Date.now() })); } catch(e){}

      /* ── Met à jour le conv en mémoire + rendu DOM direct ── */
      var _grpChatBox  = document.getElementById('chat-messages');
      var _grpChatOpen = _chatConvId === conv.id && _grpChatBox;

      newMsgsGrp.forEach(function(m) {
        if (conv.messages.some(function(x){ return String(x.id) === String(m.id); })) return;
        conv.messages.push(m);

        /* Rendu direct — évite le bug _pollGroupMessages / convMap déjà rempli */
        if (_grpChatOpen && m.from !== _currentUser.email) {
          if (!_grpChatBox.querySelector('[data-msg-id="' + m.id + '"]')) {
            var _grpRow = document.createElement('div');
            if (m.from === 'system') {
              _grpRow.className = 'chat-sys-msg';
              _grpRow.textContent = m.text || '';
            } else {
              var _sProfile = loadUserProfile(m.from) || {};
              var _sName    = _sProfile.nom || m.from || '';
              var _sAv = _sProfile.photo
                ? '<img src="' + _sProfile.photo + '" class="chat-group-av" alt="">'
                : '<div class="chat-group-av chat-group-av-init">' + escHtml(_sName.charAt(0).toUpperCase()) + '</div>';
              var _sHdr = '<div class="chat-group-sender-row">' + _sAv +
                '<span class="chat-group-sender-name">' + escHtml(_sName) + '</span></div>';
              _grpRow.className = 'chat-msg-row theirs';
              _grpRow.setAttribute('data-msg-id', m.id);
              _grpRow.innerHTML = _sHdr + _buildBubbleHtml(m, false);
            }
            _grpChatBox.appendChild(_grpRow);
          }
        }
      });

      conv.messages.sort(function(a,b){ return (Number(a.id)||0)-(Number(b.id)||0); });
      conv.lastMsg = _lastGrpText;
      conv.lastAt  = data.lastAt || Date.now();

      if (_grpChatOpen) {
        try { _scrollChatToBottom(); } catch(e4){}
      } else {
        conv.unread = (conv.unread || 0) + newMsgsGrp.filter(function(m) {
          return m.from !== _currentUser.email;
        }).length;
      }
      renderConversations();
    }
  } catch(e){}
}

/* ── Active le listener notifs pour un utilisateur ── */
function _gwFbWatchUserNotifs(email) {
  if (!_gwFbReady || !_gwFbDB || !email) return;
  _gwFbDB.ref('gw/notifs/' + _gwFbKey(email)).on('value', function(snap) {
    if (_gwFbSkip) return;
    var data = snap.val();
    if (data === null) return;
    _gwFbSkip = true;
    localStorage.setItem('gw_notifs_' + email, JSON.stringify(data));
    _gwFbSkip = false;
    try { renderNotifs(); updateNotifBadge(); } catch(e){}
  });
}

/* ── Active le listener abonnés (index inversé gw/followers/{myFbKey}) ── */
function _gwFbWatchFollowers(email) {
  if (!_gwFbReady || !_gwFbDB || !email) return;
  _gwFbDB.ref('gw/followers/' + _gwFbKey(email)).on('value', function(snap) {
    try {
      var data = snap.val();
      /* Convertit l'objet {fbKey: {nom,email,role}} en tableau */
      var followers = data
        ? Object.values(data).filter(function(f) { return f && f.email; })
        : [];
      localStorage.setItem('gw_followers_' + email, JSON.stringify(followers));
      /* Met à jour pstat-followers si le profil perso est affiché */
      var myKey  = getProfileKey({ nom: _currentUser ? _currentUser.nom : '', email: email });
      var follEl = document.getElementById('pstat-followers');
      if (follEl && _currentUser && _currentUser.email === email) {
        follEl.textContent = _getTotalFollowers(myKey, false);
      }
    } catch(e){}
  });
}

/* ── Upload initial : envoie le localStorage existant vers Firebase ── */
function _gwFbUploadAll() {
  if (!_gwFbReady) { showToast('Firebase non connecté', 'err'); return; }
  if (!confirm('Envoyer toutes les données locales vers Firebase ?')) return;
  var pairs = [
    ['users',          'gw_users'],
    ['bans',           'gw_bans'],
    ['ban_appeals',    'gw_ban_appeals'],
    ['admins',         'gw_admins'],
    ['sadmin',         'gw_sadmin'],
    ['official_posts', 'gw_official_posts'],
    ['admin_log',      'gw_admin_log'],
    ['settings_logo',  'gw_official_logo'],
  ];
  pairs.forEach(function(p) {
    var raw = localStorage.getItem(p[1]);
    if (raw) { try { _gwFbSet(p[0], JSON.parse(raw)); } catch(e){} }
  });
  /* Reports + Notifs par utilisateur */
  Object.keys(localStorage).forEach(function(k) {
    if (k.startsWith('gw_reports_')) {
      var em = k.replace('gw_reports_', '');
      try { _gwFbSet('reports/' + _gwFbKey(em), JSON.parse(localStorage.getItem(k))); } catch(e){}
    }
    if (k.startsWith('gw_notifs_')) {
      var em = k.replace('gw_notifs_', '');
      try { _gwFbSet('notifs/' + _gwFbKey(em), JSON.parse(localStorage.getItem(k))); } catch(e){}
    }
  });
  showToast('Données envoyées vers Firebase ✓', 'ok');
}

/* ── Indicateur de statut Firebase (retourne HTML) ── */
function _gwFbStatusHtml() {
  if (!_gwFbReady) {
    return '<span style="display:inline-flex;align-items:center;gap:5px;font-size:12px;color:#EF4444">' +
           '<i class="fas fa-circle" style="font-size:8px"></i> Non connecté (mode local)</span>';
  }
  return '<span style="display:inline-flex;align-items:center;gap:5px;font-size:12px;color:#10B981">' +
         '<i class="fas fa-circle" style="font-size:8px"></i> Firebase connecté — Sync temps réel actif</span>';
}

/* ══════════════════════════════════════════
   GOOGLE SIGN-IN
   ─────────────────────────────────────────
   IMPORTANT : remplacez la valeur ci-dessous
   par votre Client ID Google Cloud Console.
   https://console.cloud.google.com/
   → APIs & Services → Credentials → OAuth 2.0
══════════════════════════════════════════ */
var GW_GOOGLE_CLIENT_ID = '180664489098-gljui5ih2883jv3f6744c6t65ce650kh.apps.googleusercontent.com';

/* ── Email par défaut suggéré pour le compte super admin ── */
var GW_SUPER_ADMIN_EMAIL = 'admin@geniwork.app';

/* ── Clé unique du compte officiel Geniwork (pas un vrai email) ── */
var GW_OFFICIAL_KEY = 'geniwork__officiel';

/* Initialise GIS dès que la bibliothèque est prête */
function _initGoogleSignIn() {
  if (typeof google === 'undefined' || !google.accounts) return;
  /* Désactive le One Tap automatique — on utilise le sélecteur de compte OAuth2 */
  if (google.accounts.id) {
    google.accounts.id.initialize({
      client_id         : GW_GOOGLE_CLIENT_ID,
      callback          : _handleGoogleCredential,
      auto_select       : false,
      cancel_on_tap_outside: true,
      ux_mode           : 'popup',
      itp_support       : true
    });
    /* Désactive le One Tap automatique pour éviter qu'il apparaisse tout seul */
    google.accounts.id.cancel();
  }
}

/* Décode un JWT sans bibliothèque (partie payload seulement) */
function _decodeJWT(token) {
  try {
    var parts   = token.split('.');
    var payload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    /* Padding base64 */
    while (payload.length % 4) payload += '=';
    return JSON.parse(atob(payload));
  } catch (e) {
    return null;
  }
}

/* ── Verrou anti-double-clic ── */
var _gwGoogleRunning = false;

/* Lance Google Sign-In via Firebase Auth (pas d'origin_mismatch, localhost autorisé par défaut) */
function startGoogleSignIn() {
  if (_gwGoogleRunning) return;

  /* ── Vérifie que Firebase Auth est disponible ── */
  var authInstance = _gwFbAuth || (typeof firebase !== 'undefined' && firebase.apps && firebase.apps.length ? firebase.auth() : null);
  if (!authInstance) {
    showToast('Service Google non disponible', 'err');
    return;
  }

  _gwGoogleRunning = true;
  _showGoogleLoading('Ouverture Google…');

  var provider = new firebase.auth.GoogleAuthProvider();
  /* Force l'affichage du sélecteur de compte même si déjà connecté */
  provider.setCustomParameters({ prompt: 'select_account' });
  /* Demande email + profil */
  provider.addScope('email');
  provider.addScope('profile');

  authInstance.signInWithPopup(provider)
    .then(function(result) {
      _gwGoogleRunning = false;
      var user = result.user;
      if (!user || !user.email) {
        _hideGoogleLoading();
        showToast('Impossible de récupérer le profil Google', 'err');
        return;
      }
      _showGoogleLoading('Connexion en cours…');
      _googleLogin({
        googleId : user.uid,
        email    : user.email,
        nom      : user.displayName || user.email,
        photo    : user.photoURL    || null,
        verified : user.emailVerified
      });
    })
    .catch(function(error) {
      _gwGoogleRunning = false;
      _hideGoogleLoading();
      /* Popup fermée par l'utilisateur → silencieux */
      if (error.code === 'auth/popup-closed-by-user' ||
          error.code === 'auth/cancelled-popup-request') return;
      /* Popup bloquée */
      if (error.code === 'auth/popup-blocked') {
        showToast('Popup bloquée — autorisez les popups pour ce site', 'err');
        return;
      }
      showToast('Erreur Google : ' + (error.message || error.code), 'err');
    });
}

/* Récupère le profil via l'API userinfo Google */
function _fetchGoogleUserProfile(accessToken) {
  fetch('https://www.googleapis.com/oauth2/v3/userinfo', {
    headers: { Authorization: 'Bearer ' + accessToken }
  })
  .then(function(r) { return r.json(); })
  .then(function(info) {
    if (!info || !info.email) {
      _hideGoogleLoading();
      showToast('Impossible de récupérer le profil Google', 'err');
      return;
    }
    _googleLogin({
      googleId : info.sub,
      email    : info.email,
      nom      : info.name    || info.email,
      photo    : info.picture || null,
      verified : info.email_verified
    });
  })
  .catch(function() {
    _hideGoogleLoading();
    showToast('Erreur réseau. Réessayez.', 'err');
  });
}

/* Callback GIS token (fallback) */
function _handleGoogleToken(tokenResponse) {
  if (!tokenResponse || tokenResponse.error) { _hideGoogleLoading(); return; }
  _showGoogleLoading('Connexion en cours…');
  _fetchGoogleUserProfile(tokenResponse.access_token);
}

/* Callback GIS One Tap : reçoit un credential JWT */
function _handleGoogleCredential(response) {
  var payload = _decodeJWT(response.credential);
  if (!payload) {
    _hideGoogleLoading();
    showToast('Réponse Google invalide', 'err');
    return;
  }
  _googleLogin({
    googleId: payload.sub,
    email:    payload.email,
    nom:      payload.name,
    photo:    payload.picture,
    verified: payload.email_verified
  });
}

/* Crée ou connecte un compte via Google */
function _googleLogin(gUser) {
  _showGoogleLoading('Finalisation…');
  var email = (gUser.email || '').toLowerCase();

  /* Toujours vérifier Firebase en priorité pour éviter les doublons */
  function _doGoogleLogin(users) {
    var existing = null;

    /* 1. Cherche par googleId */
    existing = users.find(function(u) { return u.googleId === gUser.googleId; });

    /* 2. Cherche par email */
    if (!existing) {
      existing = users.find(function(u) { return u.email.toLowerCase() === email; });
      if (existing) {
        existing.googleId = gUser.googleId;
        saveUsers(users);
      }
    }

    /* 3. Crée le compte si vraiment nouveau */
    if (!existing) {
      existing = {
        nom:      gUser.nom,
        email:    email,
        password: null,
        verified: true,
        googleId: gUser.googleId,
        loginMethod: 'google'
      };
      users.push(existing);
      saveUsers(users);
    }

    /* Sync localStorage avec la liste Firebase */
    try { localStorage.setItem('gw_users', JSON.stringify(users)); } catch(e){}

    /* Importe/met à jour la photo Google dans le profil */
    if (gUser.photo) _importGooglePhoto(email, gUser.nom, gUser.photo);

    setTimeout(function() {
      _hideGoogleLoading();
      if (!_gwCheckBanOnLogin(existing.email)) return;
      _currentUser = { nom: existing.nom, email: existing.email, loginMethod: 'google' };
      _gwCreateSession(_currentUser);
      _gwPreloadUserData(_currentUser, function() {
        goTo('screen-app');
        initApp(_currentUser);
        showToast('Bienvenue ' + existing.nom + ' !', 'ok');
      });
    }, 600);
  }

  /* Charge les utilisateurs depuis Firebase d'abord */
  if (_gwFbReady && _gwFbDB) {
    _gwFbDB.ref('gw/users').once('value').then(function(snap) {
      var fbUsers = snap.val();
      var users = Array.isArray(fbUsers) ? fbUsers : getUsers();
      _doGoogleLogin(users);
    }).catch(function() {
      _doGoogleLogin(getUsers());
    });
  } else {
    _doGoogleLogin(getUsers());
  }

}

/* Importe la photo Google → profil Geniwork (canvas resize) */
function _importGooglePhoto(email, nom, photoUrl) {
  var profile = loadUserProfile(email) || getDefaultProfile({ nom: nom, email: email });
  /* Règle absolue : si une photo existe déjà (quelle qu'elle soit),
     on ne la remplace JAMAIS automatiquement.
     L'utilisateur peut toujours changer sa photo manuellement dans le profil. */
  if (profile.photo) return;
  var img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = function() {
    var canvas = document.createElement('canvas');
    var maxSz  = 180;
    var ratio  = Math.min(maxSz / img.width, maxSz / img.height, 1);
    canvas.width  = Math.round(img.width  * ratio);
    canvas.height = Math.round(img.height * ratio);
    canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
    profile.photo       = canvas.toDataURL('image/jpeg', 0.72);
    profile._googlePhoto = true;  /* marqueur : photo vient de Google */
    saveUserProfile(email, profile);
    /* Rafraîchit les avatars si l'utilisateur est déjà connecté */
    if (_currentUser && _currentUser.email === email) {
      _onProfileSaved();
    }
  };
  img.onerror = function() {
    /* Impossible de charger la photo (CORS) — on ignore */
  };
  img.src = photoUrl;
}

/* Overlay chargement */
function _showGoogleLoading(msg) {
  var ov = document.getElementById('google-loading');
  var msgEl = document.getElementById('google-loading-msg');
  if (ov)    ov.classList.remove('hidden');
  if (msgEl) msgEl.textContent = msg || 'Connexion avec Google…';
}
function _hideGoogleLoading() {
  var ov = document.getElementById('google-loading');
  if (ov) ov.classList.add('hidden');
}

/* ══════════════════════════════════════════
   DÉMARRAGE APP — Firebase charge en premier
══════════════════════════════════════════ */

/* Précharge les données spécifiques à un utilisateur depuis Firebase */
function _gwPreloadUserData(user, callback) {
  if (!_gwFbReady || !_gwFbDB || !user || !user.email) {
    callback(); return;
  }
  var fbKey = _gwFbKey(user.email);
  Promise.all([
    _gwFbDB.ref('gw/inboxes/' + fbKey).once('value'),         /* 0 */
    _gwFbDB.ref('gw/notifs/' + fbKey).once('value'),          /* 1 */
    _gwFbDB.ref('gw/profiles/' + fbKey).once('value'),        /* 2 */
    _gwFbDB.ref('gw/dms').once('value'),                      /* 3 */
    _gwFbDB.ref('gw/group_inboxes/' + fbKey).once('value'),   /* 4 */
    _gwFbDB.ref('gw/group_msgs').once('value'),               /* 5 */
    _gwFbDB.ref('gw/following/' + fbKey).once('value'),       /* 6 */
    _gwFbDB.ref('gw/follow_counts').once('value'),            /* 7 */
    _gwFbDB.ref('gw/dm_msgs').once('value'),                  /* 8 */
    _gwFbDB.ref('gw/projects/' + fbKey).once('value'),        /* 9 */
    _gwFbDB.ref('gw/services/' + fbKey).once('value'),        /* 10 */
    _gwFbDB.ref('gw/blocked/' + fbKey).once('value'),         /* 11 */
    _gwFbDB.ref('gw/privacy/' + fbKey).once('value'),         /* 12 */
    _gwFbDB.ref('gw/collab_invites/' + fbKey).once('value'),  /* 13 */
    _gwFbDB.ref('gw/reviews/' + fbKey).once('value'),         /* 14 */
    _gwFbDB.ref('gw/milestones/' + fbKey).once('value'),      /* 15 */
    _gwFbDB.ref('gw/viewed_vids/' + fbKey).once('value')      /* 16 */
  ]).then(function(snaps) {
    var inboxRaw = snaps[0].val();
    if (inboxRaw) {
      /* Firebase stocke sous forme d'objet {fromFbKey: entry} — convertir en tableau */
      var inboxList = Array.isArray(inboxRaw) ? inboxRaw : Object.values(inboxRaw);
      try { localStorage.setItem('gw_dm_inbox_' + user.email, JSON.stringify(inboxList)); } catch(e){}
    }
    var notifs = snaps[1].val();
    if (notifs) try { localStorage.setItem('gw_notifs_' + user.email, JSON.stringify(notifs)); } catch(e){}
    var profile = snaps[2].val();
    {
      var existing = loadUserProfile(user.email) || {};
      var merged;
      if (profile) {
        if (profile.photo) {
          /* Firebase a une photo.
             Règle : si Firebase a une photo Google (_googlePhoto=true) ET
             que le local a une photo différente (custom, _googlePhoto=false)
             → préférer la photo locale + resync Firebase */
          var _fbHasGooglePhoto = profile._googlePhoto && !existing._googlePhoto && existing.photo;
          if (_fbHasGooglePhoto) {
            merged = Object.assign({}, profile, { photo: existing.photo, _googlePhoto: false });
            try { _pushProfileToFirebase(user.email, merged); } catch(e){}
          } else {
            merged = Object.assign({}, existing, profile);
          }
        } else if (existing.photo) {
          /* Firebase n'a pas de photo mais locale oui → fusion + re-push compressé */
          merged = Object.assign({}, profile, { photo: existing.photo });
          try { _pushProfileToFirebase(user.email, merged); } catch(e){}
        } else {
          merged = Object.assign({}, existing, profile);
        }
      } else {
        /* Pas de profil Firebase du tout → crée-le depuis le local */
        merged = Object.assign({}, existing);
        if (merged && Object.keys(merged).length) {
          try { _pushProfileToFirebase(user.email, merged); } catch(e){}
        }
      }
      if (merged && Object.keys(merged).length) {
        /* Dernier recours : si aucune source n'a de photo, tente la sauvegarde dédiée */
        if (!merged.photo) {
          var _photoBackup = localStorage.getItem('gw_photo_' + user.email);
          if (_photoBackup) {
            merged.photo = _photoBackup;
            /* Re-pousse vers Firebase pour resynchroniser */
            try { _pushProfileToFirebase(user.email, merged); } catch(e){}
          }
        }
        /* Rétrocompat : si photo Firebase Storage mais flag Google encore actif → le reset */
        if (merged.photo && merged._googlePhoto &&
            merged.photo.indexOf('firebasestorage') !== -1) {
          merged._googlePhoto = false;
          try { _pushProfileToFirebase(user.email, merged); } catch(e){}
        }
        try { localStorage.setItem('gw_profile_' + user.email, JSON.stringify(merged)); } catch(e){}
      }
    }
    /* snaps[3] = gw/dms (ancien chemin, remplacé par gw/dm_msgs — ignoré) */

    /* ── Inbox groupes (invitations reçues sur d'autres appareils) ── */
    var grpInbox = snaps[4].val();
    if (grpInbox) {
      try {
        var _grpInboxList = Array.isArray(grpInbox) ? grpInbox : Object.values(grpInbox);
        var _grpInboxKey2 = 'gw_group_inbox_' + String(user.email).replace(/[^a-z0-9@._]/gi, '_');
        localStorage.setItem(_grpInboxKey2, JSON.stringify(_grpInboxList));
      } catch(e){}
    }

    /* ── Messages de groupe (groupes dont l'utilisateur est membre) ── */
    var allGrpMsgs = snaps[5].val() || {};
    /* On charge tous les groupes — le filtre se fera dans _checkGroupInbox / _loadGroupConvs */
    Object.keys(allGrpMsgs).forEach(function(grpFbKey) {
      var grpData = allGrpMsgs[grpFbKey];
      if (!grpData || !Array.isArray(grpData.messages)) return;
      var grpLsKey = grpFbKey.replace(/__d__/g, '.').replace(/__a__/g, '@');
      try {
        var existGrp = null;
        try { existGrp = JSON.parse(localStorage.getItem(grpLsKey)); } catch(e2){}
        var storedGrpMsgs = (existGrp && Array.isArray(existGrp.messages)) ? existGrp.messages : [];
        var grpMap = {};
        storedGrpMsgs.forEach(function(m) { grpMap[String(m.id)] = true; });
        var mergedGrp = storedGrpMsgs.slice();
        grpData.messages.forEach(function(m) {
          if (m && m.id && !grpMap[String(m.id)]) { mergedGrp.push(m); }
        });
        mergedGrp.sort(function(a,b){ return (Number(a.id)||0)-(Number(b.id)||0); });
        localStorage.setItem(grpLsKey, JSON.stringify({ messages: mergedGrp, lastMsg: grpData.lastMsg, lastAt: grpData.lastAt }));
      } catch(e){}
    });

    /* dm_msgs : les messages sont chargés depuis Firebase à l'ouverture de chaque conv (_dmOpen) */

    /* ── Following list (restaurée depuis Firebase au login) ── */
    var followingFb = snaps[6] ? snaps[6].val() : null;
    if (followingFb && Array.isArray(followingFb)) {
      try { localStorage.setItem('gw_following_' + user.email, JSON.stringify(followingFb)); } catch(e){}
    }

    /* ── Compteurs d'abonnés de tous les utilisateurs ── */
    var fcAll = snaps[7] ? snaps[7].val() : null;
    if (fcAll && typeof fcAll === 'object') {
      Object.keys(fcAll).forEach(function(fbKey) {
        var count = fcAll[fbKey];
        if (typeof count === 'number') {
          /* Décoder la clé Firebase (encodée) vers email brut pour localStorage */
          var lsKey = fbKey.replace(/__d__/g, '.').replace(/__a__/g, '@');
          localStorage.setItem('gw_fc_' + lsKey, count);
        }
      });
    }

    /* ── Projets ── */
    var projectsFb = snaps[9] ? snaps[9].val() : null;
    if (projectsFb && Array.isArray(projectsFb)) {
      try { localStorage.setItem('gw_projects_' + user.email, JSON.stringify(projectsFb)); } catch(e){}
    }

    /* ── Services ── */
    var servicesFb = snaps[10] ? snaps[10].val() : null;
    if (servicesFb && Array.isArray(servicesFb)) {
      try { localStorage.setItem('gw_services_' + user.email, JSON.stringify(servicesFb)); } catch(e){}
    }

    /* ── Utilisateurs bloqués ── */
    var blockedFb = snaps[11] ? snaps[11].val() : null;
    if (blockedFb && Array.isArray(blockedFb)) {
      try { localStorage.setItem('gw_blocked_' + user.email, JSON.stringify(blockedFb)); } catch(e){}
    }

    /* ── Paramètres de confidentialité ── */
    var privacyFb = snaps[12] ? snaps[12].val() : null;
    if (privacyFb && typeof privacyFb === 'object') {
      try { localStorage.setItem('gw_privacy_' + user.email, JSON.stringify(privacyFb)); } catch(e){}
    }

    /* ── Invitations de collaboration ── */
    var collabInvFb = snaps[13] ? snaps[13].val() : null;
    if (collabInvFb && Array.isArray(collabInvFb)) {
      try { localStorage.setItem('gw_collab_invites_' + user.email, JSON.stringify(collabInvFb)); } catch(e){}
    }

    /* ── Avis reçus sur le profil ── */
    var reviewsFb = snaps[14] ? snaps[14].val() : null;
    if (reviewsFb && Array.isArray(reviewsFb)) {
      try { localStorage.setItem('gw_reviews_' + user.email, JSON.stringify(reviewsFb)); } catch(e){}
    }

    /* ── Milestones (badges de jalons déjà déclenchés) ── */
    var milestonesFb = snaps[15] ? (snaps[15].val() || {}) : {};
    Object.keys(milestonesFb).forEach(function(k) {
      if (milestonesFb[k]) localStorage.setItem('gw_mile_' + k, '1');
    });

    /* ── Vidéos déjà vues (pour ne pas recompter) ── */
    var viewedFb = snaps[16] ? snaps[16].val() : null;
    if (viewedFb && typeof viewedFb === 'object') {
      try { localStorage.setItem('gw_viewed_vids_' + user.email, JSON.stringify(viewedFb)); } catch(e){}
    }

    callback();
  }).catch(function() { callback(); });
}

/* Lance l'app après que Firebase a chargé les données critiques */
function _gwStartApp() {
  var session = _gwLoadSession();
  if (session) {
    var storedUser = findUser(session.email);
    if (storedUser && !_admIsBanned(session.email)) {
      _currentUser = { nom: storedUser.nom, email: storedUser.email, loginMethod: storedUser.loginMethod || 'email' };
      _gwCreateSession(_currentUser);
      /* Précharge les DMs, inbox et données utilisateur depuis Firebase (même chemin que doLogin)
         avant d'initialiser l'app — garantit que les messages reçus hors connexion sont visibles */
      _gwPreloadUserData(_currentUser, function() {
        initApp(_currentUser);
        scheduleNewPosts();
        goTo('screen-app');
      });
    } else {
      localStorage.removeItem('gw_session');
    }
  }
}

/* Précharge toutes les données Firebase dans localStorage, PUIS lance l'app */
function _gwFbPreloadAndStart() {
  if (!_gwFbReady || !_gwFbDB) {
    _gwStartApp();
    return;
  }

  Promise.all([
    _gwFbDB.ref('gw/users').once('value'),
    _gwFbDB.ref('gw/posts').once('value'),
    _gwFbDB.ref('gw/bans').once('value'),
    _gwFbDB.ref('gw/official_posts').once('value'),
    _gwFbDB.ref('gw/mk_listings').once('value'),
    _gwFbDB.ref('gw/collab_requests').once('value'),
    _gwFbDB.ref('gw/profiles').once('value')
  ]).then(function(snaps) {

    /* ── Utilisateurs ── */
    var users = snaps[0].val();
    if (Array.isArray(users) && users.length) {
      try { localStorage.setItem('gw_users', JSON.stringify(users)); } catch(e){}
    }

    /* ── Posts de tous les utilisateurs ── */
    var allPosts = snaps[1].val() || {};
    Object.keys(allPosts).forEach(function(pk) {
      var pv = allPosts[pk];
      if (!Array.isArray(pv)) return;
      var pe = pk.replace(/__d__/g, '.').replace(/__a__/g, '@');
      try { localStorage.setItem('gw_userposts_' + pe, JSON.stringify(pv)); } catch(e){}
    });

    /* ── Bans ── */
    var bans = snaps[2].val();
    if (bans) try { localStorage.setItem('gw_bans', JSON.stringify(bans)); } catch(e){}

    /* ── Publications officielles ── */
    var offPosts = snaps[3].val();
    if (offPosts) try { localStorage.setItem('gw_official_posts', JSON.stringify(offPosts)); } catch(e){}

    /* ── Marketplace ── */
    var mk = snaps[4].val();
    if (mk) try { localStorage.setItem('gw_mk_listings', JSON.stringify(mk)); } catch(e){}

    /* ── Collaborations ── */
    var collab = snaps[5].val();
    if (collab) try { localStorage.setItem('gw_collab_requests', JSON.stringify(collab)); } catch(e){}

    /* ── Profils de tous les utilisateurs (photos comprises) ── */
    var allProfiles = snaps[6].val() || {};
    Object.keys(allProfiles).forEach(function(fbKey) {
      var profile = allProfiles[fbKey];
      if (!profile) return;
      var email = fbKey.replace(/__d__/g, '.').replace(/__a__/g, '@');
      try {
        var existing = null;
        try { existing = JSON.parse(localStorage.getItem('gw_profile_' + email)); } catch(e2){}
        /* Garde la photo locale si Firebase n'en a pas */
        var _hasLocalPhotoOnly = !!(existing && existing.photo && !profile.photo);
        /* Fusionne existing + Firebase (existing en base, Firebase par-dessus) pour ne perdre aucune donnée locale */
        var merged = Object.assign({}, existing || {}, profile, _hasLocalPhotoOnly ? { photo: existing.photo } : {});
        localStorage.setItem('gw_profile_' + email, JSON.stringify(merged));
        /* Re-push vers Firebase si la photo est locale mais absente de Firebase */
        if (_hasLocalPhotoOnly) {
          try { _pushProfileToFirebase(email, merged); } catch(e2){}
        }
      } catch(e){}
    });

    _gwStartApp();
  }).catch(function() {
    /* En cas d'erreur réseau, démarre quand même avec le cache local */
    _gwStartApp();
  });
}

/* Lance l'initialisation GIS quand la page est prête */
window.addEventListener('load', function() {
  /* ── IndexedDB vidéo ── */
  _gwInitVideoDB();
  /* ── Firebase : init + auth + sync + preload (tout enchaîné dans _gwInitFirebase) ── */
  _gwInitFirebase();

  /* GIS se charge de manière async — on attend qu'il soit dispo */
  var _gisTimer = setInterval(function() {
    if (typeof google !== 'undefined' && google.accounts) {
      clearInterval(_gisTimer);
      _initGoogleSignIn();
    }
  }, 200);
  /* Abandon après 10s */
  setTimeout(function() { clearInterval(_gisTimer); }, 10000);
});

/* ══════════════════════════════════════════
   NAVIGATION
══════════════════════════════════════════ */
function goTo(screenId) {
  /* ── Vérification ban en temps réel (si ban appliqué pendant session) ── */
  if (_currentUser && screenId === 'screen-app') {
    var activeBan = _admGetBanInfo(_currentUser.email);
    if (activeBan) {
      /* Invalide la session et redirige vers écran ban */
      localStorage.removeItem('gw_session');
      _currentUser = null;
      document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });
      document.getElementById('screen-login').classList.add('active');
      setTimeout(function() { _gwShowLoginBanScreen(activeBan.email || '', activeBan); }, 200);
      return;
    }
  }
  document.querySelectorAll('.screen').forEach(function(s) {
    s.classList.remove('active');
  });
  document.getElementById(screenId).classList.add('active');
}

/* ══════════════════════════════════════════
   STOCKAGE UTILISATEURS (localStorage)
   Structure : [{ nom, email, password, verified }]
══════════════════════════════════════════ */
function getUsers() {
  return JSON.parse(localStorage.getItem('gw_users') || '[]');
}
function saveUsers(users) {
  localStorage.setItem('gw_users', JSON.stringify(users));
  if (!_gwFbSkip) _gwFbSet('users', users);
}
function findUser(email) {
  return getUsers().find(function(u) {
    return u.email.toLowerCase() === email.toLowerCase();
  });
}

/* ══════════════════════════════════════════
   MODULE SÉCURITÉ — GENIWORK
   • Hachage PBKDF2 (Web Crypto API)
   • Protection brute-force (5 essais / 60 s)
   • Session sécurisée (token aléatoire + expiration 7 j)
   • Sanitisation des entrées
══════════════════════════════════════════ */

/* ── Sanitisation ── */
function _gwSanitize(str, maxLen) {
  if (typeof str !== 'string') return '';
  str = str.replace(/[<>"'`\\]/g, '');      // retire les caractères dangereux
  return str.trim().slice(0, maxLen || 512);
}

/* ── Génère un sel hexadécimal aléatoire (16 octets = 32 hex) ── */
function _gwSalt() {
  var buf = new Uint8Array(16);
  crypto.getRandomValues(buf);
  return Array.from(buf).map(function(b) { return ('0' + b.toString(16)).slice(-2); }).join('');
}

/* ── Génère un token de session aléatoire (32 octets) ── */
function _gwToken() {
  var buf = new Uint8Array(32);
  crypto.getRandomValues(buf);
  return Array.from(buf).map(function(b) { return ('0' + b.toString(16)).slice(-2); }).join('');
}

/* ── Hachage PBKDF2 asynchrone ──
   Format stocké : "pbkdf2:<sel_hex>:<hash_hex>"
   50 000 itérations, SHA-256, 256 bits
*/
function _gwHashPwd(password, salt) {
  return new Promise(function(resolve, reject) {
    try {
      var enc = new TextEncoder();
      crypto.subtle.importKey(
        'raw', enc.encode(password), { name: 'PBKDF2' }, false, ['deriveBits']
      ).then(function(key) {
        var saltBuf = new Uint8Array(salt.match(/.{2}/g).map(function(h) { return parseInt(h, 16); }));
        return crypto.subtle.deriveBits(
          { name: 'PBKDF2', salt: saltBuf, iterations: 50000, hash: 'SHA-256' },
          key, 256
        );
      }).then(function(bits) {
        var hashHex = Array.from(new Uint8Array(bits))
          .map(function(b) { return ('0' + b.toString(16)).slice(-2); }).join('');
        resolve('pbkdf2:' + salt + ':' + hashHex);
      }).catch(reject);
    } catch (e) { reject(e); }
  });
}

/* ── Vérifie un mot de passe face au hash stocké ──
   Gère automatiquement l'ancien format texte brut (migration transparente).
*/
function _gwVerifyPwd(password, stored) {
  return new Promise(function(resolve) {
    if (!stored) { resolve(false); return; }

    /* Ancien mot de passe en texte clair → comparaison directe */
    if (stored.indexOf('pbkdf2:') !== 0) {
      resolve(stored === password);
      return;
    }

    /* Nouveau format PBKDF2 */
    var parts = stored.split(':');
    if (parts.length !== 3) { resolve(false); return; }
    var salt = parts[1];
    _gwHashPwd(password, salt).then(function(computed) {
      /* Comparaison sécurisée (longueur constante simulée en JS) */
      var a = computed, b = stored;
      var diff = a.length ^ b.length;
      for (var i = 0; i < Math.min(a.length, b.length); i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
      resolve(diff === 0);
    }).catch(function() { resolve(false); });
  });
}

/* ── Protection brute-force ──
   Clé = "login:<email>" ou "reset:<email>"
   Max 5 tentatives en 60 secondes, puis blocage 60 s.
*/
var _gwAttempts = {};  /* { "login:email": { count: 0, lockedUntil: 0 } } */

function _gwCheckBrute(key) {
  /* Retourne true si l'accès est autorisé, false si bloqué */
  var now = Date.now();
  var rec = _gwAttempts[key];
  if (!rec) return true;
  if (rec.lockedUntil && now < rec.lockedUntil) return false;
  return true;
}

function _gwRecordFail(key) {
  var now = Date.now();
  if (!_gwAttempts[key]) _gwAttempts[key] = { count: 0, lockedUntil: 0 };
  var rec = _gwAttempts[key];

  /* Réinitialise le compteur si le blocage précédent est expiré */
  if (rec.lockedUntil && now >= rec.lockedUntil) {
    rec.count = 0; rec.lockedUntil = 0;
  }
  rec.count++;
  if (rec.count >= 5) {
    rec.lockedUntil = now + 60000;  /* bloqué 60 secondes */
    rec.count = 0;
  }
}

function _gwResetBrute(key) {
  delete _gwAttempts[key];
}

function _gwLockedSeconds(key) {
  var rec = _gwAttempts[key];
  if (!rec || !rec.lockedUntil) return 0;
  var remaining = Math.ceil((rec.lockedUntil - Date.now()) / 1000);
  return remaining > 0 ? remaining : 0;
}

/* ── Session sécurisée ──
   Stocke { token, email, nom, loginMethod, expires, deviceId } dans gw_session.
   Expiration : 365 jours — renouvelée à chaque ouverture.
   deviceId : identifiant unique de l'appareil — si changement de téléphone, session invalide.
*/

/* ── Identifiant unique de l'appareil (généré une seule fois, stocké en localStorage) ── */
function _gwGetDeviceId() {
  var key = 'gw_device_id';
  var id  = localStorage.getItem(key);
  if (!id) {
    /* Génère un ID aléatoire lié à cet appareil */
    id = 'dev_' + Math.random().toString(36).slice(2) + '_' + Date.now().toString(36);
    localStorage.setItem(key, id);
  }
  return id;
}

function _gwCreateSession(user) {
  var session = {
    token:       _gwToken(),
    email:       user.email,
    nom:         user.nom,
    loginMethod: user.loginMethod || 'email',
    deviceId:    _gwGetDeviceId(),
    expires:     Date.now() + 365 * 24 * 3600 * 1000   /* 1 an */
  };
  localStorage.setItem('gw_session', JSON.stringify(session));
  return session;
}

function _gwLoadSession() {
  try {
    var raw = localStorage.getItem('gw_session');
    if (!raw) return null;
    var s = JSON.parse(raw);
    if (!s || !s.token || !s.email || !s.expires) { localStorage.removeItem('gw_session'); return null; }
    /* Session expirée */
    if (Date.now() > s.expires) { localStorage.removeItem('gw_session'); return null; }
    /* Vérifie que c'est le même appareil */
    if (s.deviceId && s.deviceId !== _gwGetDeviceId()) { localStorage.removeItem('gw_session'); return null; }
    /* ── Renouvelle automatiquement la session à chaque ouverture ── */
    s.expires = Date.now() + 365 * 24 * 3600 * 1000;
    localStorage.setItem('gw_session', JSON.stringify(s));
    return s;
  } catch (e) { localStorage.removeItem('gw_session'); return null; }
}

/* ══════════════════════════════════════════
   VALIDATION MOT DE PASSE
   Règles : 8 cars, maj, min, chiffre, symbole
══════════════════════════════════════════ */
var PWD_RULES = {
  len: function(p) { return p.length >= 8; },
  maj: function(p) { return /[A-Z]/.test(p); },
  min: function(p) { return /[a-z]/.test(p); },
  num: function(p) { return /[0-9]/.test(p); },
  sym: function(p) { return /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?`~]/.test(p); }
};

function isPasswordValid(pwd) {
  return Object.values(PWD_RULES).every(function(fn) { return fn(pwd); });
}

/* Met à jour visuellement les règles (inscription) */
function checkPwdStrength(pwd) {
  updateRules(pwd, 'rule');
}

/* Met à jour visuellement les règles (reset password) */
function checkPwdStrength2(pwd) {
  updateRules(pwd, 'rule2');
}

function updateRules(pwd, prefix) {
  var keys = ['len','maj','min','num','sym'];
  keys.forEach(function(k) {
    var el = document.getElementById(prefix + '-' + k);
    if (!el) return;
    var ok = PWD_RULES[k](pwd);
    el.className = 'rule ' + (ok ? 'ok' : (pwd.length > 0 ? 'fail' : ''));
  });
}

/* ══════════════════════════════════════════
   GÉNÉRATEUR CODE 4 CHIFFRES
══════════════════════════════════════════ */
function generateCode() {
  return String(Math.floor(1000 + Math.random() * 9000));
}

/* ── Envoie un code par e-mail via /api/send-code ── */
function _gwMailCode(email, code, type, onDone) {
  fetch('/api/send-code', {
    method:  'POST',
    headers: { 'Content-Type': 'application/json' },
    body:    JSON.stringify({ email: email, code: code, type: type })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    if (data.ok) {
      showToast('Code envoyé à ' + email + ' 📧', 'ok');
    } else {
      showToast('Erreur envoi email : ' + (data.error || 'inconnu'), 'err');
    }
    if (onDone) onDone(!!data.ok);
  })
  .catch(function() {
    showToast('Impossible d\'envoyer l\'email. Vérifiez la connexion.', 'err');
    if (onDone) onDone(false);
  });
}

/* Codes temporaires en mémoire */
var _verifyCode = '';       // code inscription
var _verifyEmail = '';      // email en attente de vérification
var _verifyData  = null;    // données utilisateur temporaires

var _resetCode  = '';       // code reset
var _resetEmail = '';       // email en cours de reset

/* ══════════════════════════════════════════
   INSCRIPTION
══════════════════════════════════════════ */
function doRegister() {
  var nom   = _gwSanitize(document.getElementById('reg-nom').value.trim(), 100);
  var email = _gwSanitize(document.getElementById('reg-email').value.trim().toLowerCase(), 320);
  var pwd   = document.getElementById('reg-pwd').value;
  var pwd2  = document.getElementById('reg-pwd2').value;

  // Réinitialise l'erreur email
  setEmailError(false);

  /* ─ Validations ─ */
  if (!nom) {
    showToast('Veuillez entrer votre nom complet', 'err'); return;
  }
  if (!email || !email.includes('@') || !email.includes('.')) {
    showToast('Adresse e-mail invalide', 'err'); return;
  }
  if (!isPasswordValid(pwd)) {
    showToast('Le mot de passe ne respecte pas les règles', 'err'); return;
  }
  if (pwd !== pwd2) {
    showToast('Les mots de passe ne correspondent pas', 'err'); return;
  }

  /* ─ Vérification email : d'abord localStorage, puis Firebase ─ */
  if (findUser(email)) {
    setEmailError(true);
    showToast('Cette adresse e-mail est déjà utilisée', 'err'); return;
  }

  /* Vérifie aussi dans Firebase (au cas où localStorage pas encore chargé) */
  function _proceedRegister() {
    _verifyCode  = generateCode();
    _verifyEmail = email;
    _verifyData  = { nom: nom, email: email, password: pwd, verified: false };
    document.getElementById('verify-email-display').textContent = email;
    clearCodeInputs(['c1','c2','c3','c4']);
    goTo('screen-verify');
    /* Envoie le code par email (le code n'est plus affiché à l'écran) */
    _gwMailCode(email, _verifyCode, 'register');
  }

  if (_gwFbReady && _gwFbDB) {
    showToast('Vérification en cours…', 'info');
    _gwFbDB.ref('gw/users').once('value').then(function(snap) {
      var fbUsers = snap.val();
      if (Array.isArray(fbUsers) && fbUsers.find(function(u){ return u.email && u.email.toLowerCase() === email; })) {
        setEmailError(true);
        showToast('Cette adresse e-mail est déjà utilisée', 'err'); return;
      }
      _proceedRegister();
    }).catch(function() {
      _proceedRegister();
    });
  } else {
    _proceedRegister();
  }

  /* Code affiché à l'écran (démo) — production : envoi par email côté serveur */
}

function setEmailError(show) {
  var err = document.getElementById('err-email');
  var box = document.getElementById('box-reg-email');
  if (show) {
    err.classList.remove('hidden');
    box.classList.add('error');
  } else {
    err.classList.add('hidden');
    box.classList.remove('error');
  }
}

/* ══════════════════════════════════════════
   VÉRIFICATION CODE (inscription)
══════════════════════════════════════════ */
function doVerify() {
  var entered = getCodeValue(['c1','c2','c3','c4']);

  if (entered.length < 4) {
    showToast('Entrez les 4 chiffres du code', 'err'); return;
  }
  if (entered !== _verifyCode) {
    showToast('Code incorrect. Vérifiez et réessayez.', 'err');
    shakeCodeInputs(['c1','c2','c3','c4']); return;
  }

  /* ─ Code correct : hache le mot de passe et enregistre ─ */
  _verifyData.verified = true;
  var pwdToHash = _verifyData.password;
  var salt = _gwSalt();
  _gwHashPwd(pwdToHash, salt).then(function(hashed) {
    _verifyData.password = hashed;
    var users = getUsers();
    /* Double vérification : email toujours libre au moment de l'écriture */
    if (users.some(function(u) { return u.email.toLowerCase() === _verifyData.email.toLowerCase(); })) {
      showToast('Cette adresse e-mail est déjà utilisée', 'err');
      goTo('screen-login'); return;
    }
    users.push(_verifyData);
    saveUsers(users);

    _verifyCode = '';
    /* On garde _verifyData.nom pour l'accueil — on le vide après CGU */

    showToast('Compte vérifié ✓ Lisez les CGU pour continuer', 'ok');
    setTimeout(function() {
      openCGU();
    }, 1000);
  }).catch(function() {
    /* Fallback si crypto non disponible (rare) */
    var users = getUsers();
    if (users.some(function(u) { return u.email.toLowerCase() === _verifyData.email.toLowerCase(); })) {
      showToast('Cette adresse e-mail est déjà utilisée', 'err');
      goTo('screen-login'); return;
    }
    users.push(_verifyData);
    saveUsers(users);
    _verifyCode = '';
    showToast('Compte vérifié ✓ Lisez les CGU pour continuer', 'ok');
    setTimeout(function() { openCGU(); }, 1000);
  });
}

function resendCode() {
  if (!_verifyEmail) return;
  _verifyCode = generateCode();
  clearCodeInputs(['c1','c2','c3','c4']);
  _gwMailCode(_verifyEmail, _verifyCode, 'register');
}

/* ══════════════════════════════════════════
   CONNEXION
══════════════════════════════════════════ */
function doLogin() {
  var email = _gwSanitize(document.getElementById('login-email').value.trim().toLowerCase(), 320);
  var pwd   = document.getElementById('login-pwd').value;

  if (!email) {
    showToast('Veuillez entrer votre adresse e-mail', 'err'); return;
  }
  if (!email.includes('@')) {
    showToast('Adresse e-mail invalide', 'err'); return;
  }
  if (!pwd) {
    showToast('Veuillez entrer votre mot de passe', 'err'); return;
  }

  /* ── Protection brute-force ── */
  var bruteKey = 'login:' + email;
  if (!_gwCheckBrute(bruteKey)) {
    var secs = _gwLockedSeconds(bruteKey);
    showToast('Trop de tentatives. Réessayez dans ' + secs + ' s.', 'err'); return;
  }

  var user = findUser(email);

  /* Message générique : ne révèle pas si l'email existe */
  if (!user) {
    _gwRecordFail(bruteKey);
    showToast('Email ou mot de passe incorrect', 'err'); return;
  }
  /* Compte Google → inviter à utiliser le bouton Google */
  if (user.loginMethod === 'google' && !user.password) {
    showToast('Ce compte utilise Google. Cliquez sur "Continuer avec Google".', 'err'); return;
  }
  /* Compte banni */
  if (!_gwCheckBanOnLogin(email)) return;
  /* Compte non vérifié */
  if (!user.verified) {
    showToast('Compte non vérifié. Vérifiez votre e-mail.', 'err'); return;
  }

  /* ── Vérification asynchrone du mot de passe (PBKDF2) ── */
  var loginBtn = document.querySelector('#screen-login .auth-btn') || document.querySelector('#screen-login button[onclick="doLogin()"]');
  if (loginBtn) { loginBtn.disabled = true; loginBtn.textContent = 'Vérification…'; }

  _gwVerifyPwd(pwd, user.password).then(function(ok) {
    if (loginBtn) { loginBtn.disabled = false; loginBtn.textContent = 'Se connecter'; }

    if (!ok) {
      _gwRecordFail(bruteKey);
      var remaining = 5 - ((_gwAttempts[bruteKey] || {}).count || 0);
      showToast('Email ou mot de passe incorrect' + (remaining <= 2 ? ' (' + remaining + ' essai(s) restant)' : ''), 'err');
      return;
    }

    /* ── Connexion réussie ── */
    _gwResetBrute(bruteKey);

    /* Migration transparente : si mot de passe en texte clair → rehache maintenant */
    if (user.password && user.password.indexOf('pbkdf2:') !== 0) {
      var salt = _gwSalt();
      _gwHashPwd(pwd, salt).then(function(hashed) {
        var users = getUsers();
        var idx = users.findIndex(function(u) { return u.email.toLowerCase() === email; });
        if (idx !== -1) { users[idx].password = hashed; saveUsers(users); }
      });
    }

    /* Crée une session sécurisée */
    var session = _gwCreateSession(user);
    _currentUser = { nom: user.nom, email: user.email, loginMethod: user.loginMethod || 'email' };

    showToast('Connexion réussie ✓', 'ok');
    setTimeout(function() {
      _gwPreloadUserData(_currentUser, function() {
        initApp(_currentUser);
        scheduleNewPosts();
        goTo('screen-app');
      });
    }, 900);
  });
}

/* ══════════════════════════════════════════
   CGU — LOGIQUE
══════════════════════════════════════════ */

function openCGU() {
  /* Réinitialise la page CGU : décocher, désactiver bouton, remettre en haut */
  var checkbox = document.getElementById('cgu-checkbox');
  var btn      = document.getElementById('cgu-accept-btn');
  var body     = document.getElementById('cgu-body');

  if (checkbox) checkbox.checked = false;
  if (btn)      btn.disabled = true;
  if (body)     body.scrollTop = 0;

  goTo('screen-cgu');
}

/* Appelé quand l'utilisateur coche/décoche */
function onCguCheck(checkbox) {
  var btn = document.getElementById('cgu-accept-btn');
  btn.disabled = !checkbox.checked;
}

/* Appelé quand l'utilisateur clique "Accepter et continuer" */
function acceptCGU() {
  var checkbox = document.getElementById('cgu-checkbox');
  if (!checkbox.checked) return;

  /* Marque la CGU comme acceptée pour cet utilisateur */
  if (_verifyData) {
    var users = getUsers();
    var idx   = users.findIndex(function(u) {
      return u.email.toLowerCase() === _verifyData.email.toLowerCase();
    });
    if (idx !== -1) {
      users[idx].cguAccepted = true;
      saveUsers(users);
    }
    _verifyData = null;
  }

  /* _verifyEmail reste disponible même après _verifyData = null */
  var registeredEmail = _verifyEmail;

  showToast('Bienvenue sur Geniwork ✓', 'ok');
  setTimeout(function() {
    var newUser = registeredEmail ? findUser(registeredEmail) : null;
    if (newUser) {
      var sessionUser = { nom: newUser.nom, email: newUser.email, loginMethod: newUser.loginMethod || 'email' };
      _currentUser = sessionUser;
      _gwCreateSession(sessionUser);
      initApp(sessionUser);
      scheduleNewPosts();
    }
    goTo('screen-app');
  }, 1200);
}

/* ══════════════════════════════════════════
   MOT DE PASSE OUBLIÉ
══════════════════════════════════════════ */
function doForgot() {
  var email = _gwSanitize(document.getElementById('forgot-email').value.trim().toLowerCase(), 320);

  if (!email || !email.includes('@')) {
    showToast('Adresse e-mail invalide', 'err'); return;
  }

  /* ── Compte banni → impossible de réinitialiser ── */
  var banInfo = _admGetBanInfo(email);
  if (banInfo) {
    goTo('screen-login');
    setTimeout(function() { _gwShowLoginBanScreen(email, banInfo); }, 150);
    return;
  }

  var user = findUser(email);

  /* Email non enregistré — message générique (sécurité) */
  if (!user) {
    showToast('Si ce compte existe, un code a été envoyé.', '');
    /* On simule quand même pour ne pas révéler si l'email existe */
    setTimeout(function() { goTo('screen-login'); }, 2000);
    return;
  }

  /* Génère le code de réinitialisation */
  _resetCode  = generateCode();
  _resetEmail = email;

  document.getElementById('reset-email-display').textContent = email;
  clearCodeInputs(['r1','r2','r3','r4']);

  goTo('screen-reset-verify');
  /* Envoie le code par e-mail */
  _gwMailCode(email, _resetCode, 'reset');
}

/* ══════════════════════════════════════════
   VÉRIFICATION CODE (reset)
══════════════════════════════════════════ */
function doResetVerify() {
  var entered = getCodeValue(['r1','r2','r3','r4']);

  if (entered.length < 4) {
    showToast('Entrez les 4 chiffres du code', 'err'); return;
  }
  if (entered !== _resetCode) {
    showToast('Code incorrect. Vérifiez et réessayez.', 'err');
    shakeCodeInputs(['r1','r2','r3','r4']); return;
  }

  /* Réinitialise les champs du nouveau mot de passe */
  document.getElementById('new-pwd').value  = '';
  document.getElementById('new-pwd2').value = '';
  updateRules('', 'rule2');

  goTo('screen-new-pwd');
}

function resendResetCode() {
  if (!_resetEmail) return;
  _resetCode = generateCode();
  clearCodeInputs(['r1','r2','r3','r4']);
  _gwMailCode(_resetEmail, _resetCode, 'reset');
}

/* ══════════════════════════════════════════
   ENREGISTRER NOUVEAU MOT DE PASSE
══════════════════════════════════════════ */
function doSaveNewPwd() {
  var pwd  = document.getElementById('new-pwd').value;
  var pwd2 = document.getElementById('new-pwd2').value;

  if (!isPasswordValid(pwd)) {
    showToast('Le mot de passe ne respecte pas les règles', 'err'); return;
  }
  if (pwd !== pwd2) {
    showToast('Les mots de passe ne correspondent pas', 'err'); return;
  }

  /* ── Compte banni → bloquer même si le code était valide ── */
  if (_resetEmail) {
    var banInfo = _admGetBanInfo(_resetEmail);
    if (banInfo) {
      var e = _resetEmail; _resetCode = ''; _resetEmail = '';
      goTo('screen-login');
      setTimeout(function() { _gwShowLoginBanScreen(e, banInfo); }, 150);
      return;
    }
  }

  /* ── Hache le nouveau mot de passe avant de sauvegarder ── */
  var salt = _gwSalt();
  _gwHashPwd(pwd, salt).then(function(hashed) {
    var users = getUsers();
    var idx   = users.findIndex(function(u) {
      return u.email.toLowerCase() === _resetEmail.toLowerCase();
    });
    if (idx !== -1) {
      users[idx].password = hashed;
      saveUsers(users);
    }

    /* Réinitialise aussi le brute-force pour cet email */
    _gwResetBrute('login:' + _resetEmail.toLowerCase());

    _resetCode  = '';
    _resetEmail = '';

    showToast('Mot de passe mis à jour ✓', 'ok');
    setTimeout(function() {
      goTo('screen-login');
    }, 1200);
  }).catch(function() {
    showToast('Erreur lors de la mise à jour. Réessayez.', 'err');
  });
}

/* ══════════════════════════════════════════
   UTILITAIRES CODE 4 CHIFFRES
══════════════════════════════════════════ */

/* Avance automatiquement au champ suivant */
function codeNext(input, nextId) {
  input.value = input.value.replace(/[^0-9]/g, '');
  if (input.value.length === 1) {
    input.classList.add('filled');
    if (nextId) {
      var next = document.getElementById(nextId);
      if (next) next.focus();
    }
  } else {
    input.classList.remove('filled');
  }
}

/* Retour arrière vers le champ précédent */
function codePrev(event, input, prevId) {
  if (event.key === 'Backspace' && input.value === '' && prevId) {
    var prev = document.getElementById(prevId);
    if (prev) { prev.focus(); prev.value = ''; prev.classList.remove('filled'); }
  }
}

/* Lit les 4 chiffres */
function getCodeValue(ids) {
  return ids.map(function(id) {
    return document.getElementById(id).value;
  }).join('');
}

/* Vide les 4 champs */
function clearCodeInputs(ids) {
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) { el.value = ''; el.classList.remove('filled'); }
  });
}

/* Animation secousse si code incorrect */
function shakeCodeInputs(ids) {
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    el.classList.add('shake');
    el.style.borderColor = '#EF4444';
    setTimeout(function() {
      el.classList.remove('shake');
      el.style.borderColor = '';
    }, 600);
  });
}

/* ══════════════════════════════════════════
   AFFICHER / CACHER MOT DE PASSE
══════════════════════════════════════════ */
function togglePwd(inputId, btn) {
  var input = document.getElementById(inputId);
  var icon  = btn.querySelector('i');
  if (input.type === 'password') {
    input.type     = 'text';
    icon.className = 'fas fa-eye-slash';
  } else {
    input.type     = 'password';
    icon.className = 'fas fa-eye';
  }
}

/* ══════════════════════════════════════════
   TOAST
══════════════════════════════════════════ */
var _toastTimer = null;
function showToast(message, type) {
  var el = document.getElementById('toast');
  el.textContent = message;
  el.className   = 'toast show' + (type ? ' ' + type : '');
  clearTimeout(_toastTimer);
  _toastTimer = setTimeout(function() {
    el.classList.remove('show');
  }, 3000);
}

